138→    public function saveSummary(array $data): array
139→    {
140→        return DB::transaction(function () use ($data) {
141→            $sfuserId = $data['sfuser_id'];
142→            $weekStart = $data['week_start'];
143→
144→            // 加排他锁防止并发 upsert 唯一键冲突
145→            $existing = DailyReportWeeklySummary::where('sfuser_id', $sfuserId)
146→                ->where('week_start', $weekStart)
147→                ->lockForUpdate()
148→                ->first();
149→
150→            $summaryData = [
151→                'sfuser_id' => $sfuserId,
152→                'week_start' => $weekStart,
153→                'week_end' => $data['week_end'],
154→                'reporter_ids' => $data['reporter_ids'] ?? '',
155→                'cc_ids' => $data['cc_ids'] ?? '',
156→                'content' => $data['content'],
157→                'token' => $data['token'] ?? '',
158→                'submit_days' => $data['submit_days'] ?? 0,
159→                'total_chars' => $data['total_chars'] ?? 0,
160→            ];
161→
162→            $created = false;
163→            if ($existing) {
164→                $existing->update($summaryData);
165→                $summaryId = $existing->id;
166→            } else {
167→                try {
168→                    $summary = DailyReportWeeklySummary::create($summaryData);
169→                    $summaryId = $summary->id;
170→                    $created = true;
171→                } catch (\Illuminate\Database\QueryException $e) {
172→                    // 唯一键冲突兜底：并发创建时另一个事务已插入
173→                    $existing = DailyReportWeeklySummary::where('sfuser_id', $sfuserId)
174→                        ->where('week_start', $weekStart)
175→                        ->first();
176→                    $existing->update($summaryData);
177→                    $summaryId = $existing->id;
178→                }
