386→    public function getOthersDailyReportList(array $input): array
387→    {
388→        $startDate = $input['start_date'] ?? date('Y-m-d', strtotime('- 60 days'));
389→        $endDate = $input['end_date'] ?? date('Y-m-d');
390→        $beginDate = date('Y-m-d', strtotime('-60 days'));
391→        $startDate = max($beginDate, $startDate);
392→        $sfuserId = Arr::get($input, 'sfuser_info.id', 0);
393→        $nicknameHash = $input['nickname_hash_filter'] ?? [];
394→        $userIds = [];
395→        $resignedUserIds = [];  // resigned sfuser ids Array
396→        $resignationDate = [];  // id->resignation_date Map Array
397→        // 离职人员id与date
398→        $resignedUserIds = [];  // resigned sfuser ids Array
399→        $resignationDate = [];  // id->resignation_date Map Array
400→        // 新抄送人id与第一次提交日报的日历id
401→        $newReporterIds = [];   // 新抄送人id
402→        $firstReportCalendarIds = [];  // 第一次抄送时间
403→        // 查询开始和结束的日历id
404→        $startCheckDate = date('Y-m-d', strtotime($startDate) - static::CHECK_TIME);
405→        $startCalendarId = $this->getCalendarIdByDate($startDate);
406→        $endCalendarId = $this->getCalendarIdByDate($endDate);
407→        $startCheckCalendarId = $this->getCalendarIdByDate($startCheckDate);
408→        if ($nicknameHash) {
409→            // TODO: 要换SfuserHash2IdMap吗? 目前是前端传的啥nickname，就用返回谁的。
410→            $userIds = Sfuser::whereIn('nickname_hash', $nicknameHash)->where('is_closed', 0)->pluck('id')->toArray();
411→            // 单独处理离职人员
412→            $resignedUsers = Sfuser::whereIn('nickname_hash', $nicknameHash)->where('is_closed', 0)->where('status', 'resignation');
413→            if ($resignedUsers->exists()) {
414→                $resignedUsers = $resignedUsers->select('id', 'resignation_date')->get();
415→                $resignedUserIds = $resignedUsers->pluck('id')->toArray();
416→                $resignationDate = $resignedUsers->pluck('resignation_date', 'id')->toArray();
417→            }
418→
419→            foreach ($userIds as $uid) {
420→                $checkReportIds = DailyReport::where('sfuser_id', $uid)->where('calendar_id', '>=', $startCheckCalendarId)->where('calendar_id', '<', $startCalendarId)
421→                    ->where('status', DailyReport::STATUS_COMMITTED)->pluck('id')->toArray();   // 开始日期前30天内该sfuser写的日报。
422→                if (empty($checkReportIds) || !DailyReportRead::where('cdate', '>=', $startCheckDate)->where('cdate', '<=', date('Y-m-d'))->where('receiver_id', $sfuserId)->whereIn('daily_report_id', $checkReportIds)->exists()) { // 之前不曾提交/抄送日报
423→                    $reports = DailyReport::where('sfuser_id', $uid)->where('calendar_id', '>=', $startCalendarId)->where('calendar_id', '<=', $endCalendarId)
424→                        ->where('status', DailyReport::STATUS_COMMITTED)->pluck('calendar_id', 'id')->toArray();    // report_id -> calendar_id
425→                    $reportIds = array_keys($reports);  // 该月该人所有日报
426→                    $reportIds = DailyReportRead::where('cdate', '>=', $startDate)->where('cdate', '<=', date('Y-m-d'))->where('receiver_id', $sfuserId)->whereIn('daily_report_id', $reportIds)->pluck('daily_report_id')->toArray(); // 该月该人写给我的日报
427→                    // 其中抄送给我的第一封日报id,及其日历id
428→                    $firstReportId = DailyReport::whereIn('id', $reportIds)->orderBy('calendar_id')->pluck('id')->first();
429→                    if (empty($firstReportId)) {
430→                        break;
431→                    }
432→                    // 添加sfuser_id和calendar_id
433→                    $newReporterIds[] = $uid;
434→                    $firstReportCalendarIds[$uid] = $reports[$firstReportId];
435→                }
436→            }
437→        }
438→        if (empty($userIds) || empty($sfuserId)) {
439→            return [
440→                'current_page' => 1,
441→                'per_page' => $input['per_page'] ?? 5,
442→                'total' => 0,
443→                'reports' => ['report_list' => []],
444→                'lack_report' => [],
445→                'report_dates' => [],
446→            ];
447→        }
448→        $calendarIdEnd = $this->getCalendarIdByDate($endDate);
449→        $calendarIdStart = $this->getCalendarIdByDate($startDate);
450→        $reportIds = DailyReport::whereIn('sfuser_id', $userIds)->where('calendar_id', '>=', $calendarIdStart)->where('calendar_id', '<=', $calendarIdEnd)->where('status', DailyReport::STATUS_COMMITTED)->pluck('id')->toArray();
451→        $reportReadMap = DailyReportRead::where('cdate', '>=', $startDate)->where('cdate', '<=', date('Y-m-d'))->whereIn('daily_report_id', $reportIds)->where('receiver_id', $sfuserId)->pluck('is_read', 'daily_report_id')->toArray();
452→        /** @phpstan-ignore-next-line */
453→        $list = DailyReport::whereIn('id', array_keys($reportReadMap))->select(['id', 'sfuser_id', 'reporter_ids', 'cc_ids', 'content', 'files', 'report_date', 'status', 'is_late', 'calendar_id', 'data', 'created_at', 'updated_at'])->orderBy('calendar_id', 'desc')->orderByDesc('id')->paginate($input['per_page'] ?? 5)->toArray();
454→        // 获取最新的token
455→        $startTime = date('Y-m-d H:i:s', strtotime('- 60 days'));
456→        $maxIds = DailyReportRead::where('cdate', '>=', date('Y-m-d', strtotime('- 60 days')))->where('cdate', '<=', date('Y-m-d'))->where('receiver_id', $sfuserId)->whereIn('sfuser_id', $userIds)->where('created_at', '>=', $startTime)->selectRaw('max(id) as id, sfuser_id')->groupBy('sfuser_id')->get()->toArray();
457→        $reportToIdsToken = DailyReportRead::whereIn('id', array_column($maxIds, 'id'))->pluck('daily_report_id')->toArray();
458→        $tokens = $this->getTokensByReportIds($reportToIdsToken);
459→        // 处理是否已读
460→        $tmpData = $list['data'];
461→        foreach ($tmpData as $k => $tv) {
462→            $tmpData[$k]['is_read'] = $reportReadMap[$tv['id']] ?? 0;
463→        }
464→        $data['report_list'] = $tmpData;
465→        // 增加缺少日报的人和日期, 所有需要日报的日期
466→        $reportDates = DailyReport::whereIn('id', array_keys($reportReadMap))->pluck('report_date')->unique()->values()->toArray();
467→        $lackUserData = [];
468→        $lackUserDateList = DailyReportLackUser::whereIn('sfuser_id', $userIds)->where('report_date', '>=', $startDate)->where('report_date', '<=', $endDate)
469→            ->orderByDesc('calendar_id')->select(['sfuser_id', 'report_date', 'calendar_id'])->get()->toArray();
470→        // 去除离职人员，离职日期后的日报缺失；去除新抄送人，第一次抄送日期前的日报缺失
471→        if (!empty($resignedUserIds) || !empty($newReporterIds)) {
472→            foreach ($lackUserDateList as $key => $lackData) {
473→                if (in_array($lackData['sfuser_id'], $resignedUserIds)
474→                    && strtotime($lackData['report_date']) >= strtotime($resignationDate[$lackData['sfuser_id']])
475→                    || in_array($lackData['sfuser_id'], $newReporterIds)
476→                    && $firstReportCalendarIds[$lackData['sfuser_id']] > $lackData['calendar_id']
477→                ) {
478→                    unset($lackUserDateList[$key]);
479→                }
480→            }
481→        }
482→        $lackUserIds = array_unique(array_column($lackUserDateList, 'sfuser_id'));
483→        if (!empty($lackUserIds)) {
484→            $nickNameMap = Sfuser::whereIn('id', $lackUserIds)->pluck('nickname', 'id')->toArray();
485→            foreach ($lackUserDateList as $lv) {
486→                $lackUserData[$lv['report_date']][] = $nickNameMap[$lv['sfuser_id']] ?? '';
487→                $reportDates[] = $lv['report_date'];
488→            }
489→        }
490→        $reportDates = array_values(array_unique($reportDates));
491→        sort($reportDates);
492→        return [
493→            'decrypt_config' => ['tokens' => $tokens],
494→            'current_page' => $list['current_page'],
495→            'per_page' => $input['per_page'] ?? 5,
496→            'total' => $list['total'],
497→            'reports' => $data,
498→            'lack_report' => $lackUserData,
499→            'report_dates' => $reportDates,
500→        ];
501→    }
